// Ambil data dari web app (multipart/form-data)
// Field binary: 'produk_1'..'produk_10' = hingga 10 foto produk (minimal 1), 'frame' = frame acuan (opsional)
// Field text: deskripsi, spesifikasi, key_point_sell, cara_penggunaan, subjek, improvement, background
// Field toggle: gunakan_frame ('true'/'false', default aktif kalau tidak dikirim) - kalau 'false', file frame tidak wajib dan aturan frame tidak disisipkan ke prompt
// Field toggle per-gambar: varian_1_aktif..varian_6_aktif ('true'/'false', default aktif kalau tidak dikirim)
// API key TIDAK dikirim dari web - dipasang via credential Query Auth di tiap node Gemini

const item = $input.first();
const binari = item.binary || {};

const toBase64 = async (key) => {
  if (!binari[key]) return null;
  const buffer = await this.helpers.getBinaryDataBuffer(0, key);
  return {
    mime_type: binari[key].mimeType || 'image/png',
    data: buffer.toString('base64')
  };
};

// Kumpulkan semua foto produk yang ada (produk_1 s/d produk_10)
const produkParts = [];
for (let i = 1; i <= 10; i++) {
  const hasil = await toBase64('produk_' + i);
  if (hasil) produkParts.push({ inline_data: hasil });
}
if (produkParts.length === 0) {
  throw new Error('Tidak ada foto produk yang diupload. Pastikan web app upload minimal 1 foto dengan nama field: produk_1');
}

const body = item.json.body || item.json;

const gunakanFrame = body.gunakan_frame !== 'false' && body.gunakan_frame !== false;
let frameHasil = null;
if (gunakanFrame) {
  frameHasil = await toBase64('frame');
  if (!frameHasil) throw new Error('File "frame" tidak ditemukan. Pastikan web app upload frame acuan, atau kirim gunakan_frame=false untuk melewati frame acuan.');
}

const negativePrompt = (body.negative_prompt || '').trim();
const gunakanNegativePrompt = body.gunakan_negative_prompt === 'true' || body.gunakan_negative_prompt === true;
const negativeInstruksi = (gunakanNegativePrompt && negativePrompt)
  ? ('HINDARI/JANGAN tampilkan hal-hal berikut di hasil akhir: ' + negativePrompt + '.')
  : '';

const aktif = (key) => body[key] !== 'false' && body[key] !== false;
const varianAktif = {
  v1: aktif('varian_1_aktif'),
  v2: aktif('varian_2_aktif'),
  v3: aktif('varian_3_aktif'),
  v4: aktif('varian_4_aktif'),
  v5: aktif('varian_5_aktif'),
  v6: aktif('varian_6_aktif'),
  v7: aktif('varian_7_aktif')
};

return [{
  json: {
    produkParts: produkParts,
    jumlahFotoProduk: produkParts.length,
    frameB64: frameHasil ? frameHasil.data : null,
    frameMime: frameHasil ? frameHasil.mime_type : null,
    framePart: null,
    deskripsi: body.deskripsi || '',
    spesifikasi: body.spesifikasi || '',
    keyPointSell: body.key_point_sell || '',
    judulProduk: body.judul_produk || '',
    tagline: body.tagline || '',
    caraPenggunaan: body.cara_penggunaan || '',
    subjek: body.subjek || 'model manusia yang relevan',
    improvement: body.improvement || '',
    background: body.background || 'bersih dan profesional',
    warna: body.warna || '',
    negativeInstruksi: negativeInstruksi,
    varianAktif: varianAktif,
    aturanFrame: gunakanFrame ? 'ATURAN VISUAL WAJIB: buat foto iklan produk bersih dalam format square 1:1, full-bleed, tanpa elemen template apa pun. Hasil akhir harus seperti foto iklan baru yang natural, bukan desain yang ditempel di dalam bingkai. Jangan buat border, bingkai tepi, header/banner atas, tab, badge brand, watermark, garis bantu, kotak logo, atau label brand tambahan. DILARANG KERAS meniru atau menyalin ELEMEN KONTEN dari frame acuan/gambar apa pun yang dilampirkan sebagai acuan layout - termasuk judul/headline besar, tagline, kalimat promosi, badge lingkaran berisi icon, panel/inset foto lingkaran tambahan, foto varian produk lain di pojok, atau kombinasi teks+icon apa pun. Frame acuan HANYA boleh dipakai untuk menentukan rasio kanvas persegi dan posisi area aman kosong - bukan untuk ditiru desain/kontennya sama sekali. Hasil akhir harus foto produk bersih tanpa teks/judul/tagline/badge apa pun kecuali diminta eksplisit di instruksi lain.\n\nFoto-foto produk yang saya berikan adalah satu-satunya referensi visual yang boleh ditiru. Pertahankan bentuk, warna, dan detail produk secara konsisten dari semua foto referensi tersebut.' : '',
    areaKosong: 'ATURAN LAYOUT UMUM: seluruh kanvas harus terisi foto natural yang menyatu (satu pemandangan utuh), jangan ada kotak/blok/kartu warna solid, kotak putih kosong, kotak abu-abu, atau area blank/flat color apa pun di bagian mana pun dari kanvas. Jangan taruh teks, logo, badge, kotak warna, banner, header, atau bentuk dekoratif apa pun kecuali diminta eksplisit di instruksi lain. DILARANG KERAS MUTLAK menambahkan panel/kotak semi-transparan, efek kaca buram (glassmorphism/frosted glass/acrylic panel), overlay gradasi gelap, vignette buatan, drop shadow, glow, atau bayangan artifisial apa pun di belakang teks/judul/tagline/label/badge mana pun - background harus 100% foto natural bersih apa adanya, teks harus menyatu langsung di atas foto asli tanpa lapisan/efek tambahan apa pun. Elemen penting seperti produk utama, wajah model, dan teks/label yang harus terbaca jangan diletakkan mepet ke tepi kanvas; sisakan margin aman minimal 2% dari lebar/tinggi kanvas di keempat sisi.\n\nATURAN SKALA PRODUK WAJIB (paling penting, jangan diabaikan): produk WAJIB terlihat KECIL-SEDANG di dalam kanvas, zoom-out, seperti foto produk dari jarak agak jauh - BUKAN close-up. Produk utama beserta bayangan/refleksinya HANYA BOLEH mengisi maksimal 35%-45% dari lebar dan tinggi kanvas (ukur dari ujung ke ujung produk). Sisanya, yaitu minimal 55%-65% dari kanvas, WAJIB berupa ruang/background kosong yang lega mengelilingi produk di keempat sisi (atas, bawah, kiri, kanan). Bayangkan produk seperti foto thumbnail marketplace yang di-zoom out, bukan foto detail/macro. JANGAN membuat produk memenuhi sebagian besar kanvas walau itu berarti produk terlihat kecil di tengah banyak ruang kosong - itu yang diinginkan.'
  }
}];

return $input.all().map(item => {
  const resp = item.json;
  const parts = resp?.candidates?.[0]?.content?.parts || [];
  const ada = parts.some(p => p.inlineData || p.inline_data);
  return { json: { ...resp, adaGambar: ada }, pairedItem: item.pairedItem };
});

// Ekstrak gambar base64 dari respons Gemini -> jadikan binary
// Menggunakan tag 'varian' yang sudah ditempel tiap node Tag Varian N (bukan posisi/index),
// supaya tetap benar walau ada varian yang dinonaktifkan (jumlah item bisa < 6).
const out = [];

for (const item of $input.all()) {
  const resp = item.json;
  const varian = resp.varian || 'unknown';
  const parts = resp?.candidates?.[0]?.content?.parts || [];
  const imgPart = parts.find(p => p.inlineData || p.inline_data);
  if (!imgPart) {
    out.push({ json: { varian, error: 'Tidak ada gambar di respons', raw: resp } });
    continue;
  }
  const d = imgPart.inlineData || imgPart.inline_data;
  const buffer = Buffer.from(d.data, 'base64');
  const namaFile = 'produk-' + varian + '-' + Date.now() + '.png';
  out.push({
    json: { varian, fileName: namaFile, base64: d.data, mimeType: d.mimeType || d.mime_type || 'image/png' },
    binary: { data: await this.helpers.prepareBinaryData(buffer, namaFile, d.mimeType || 'image/png') }
  });
}
return out;

// Kumpulkan semua hasil jadi 1 respons untuk web app
const hasil = $input.all().map(i => ({
  varian: i.json.varian,
  fileName: i.json.fileName,
  image: 'data:' + (i.json.mimeType || 'image/png') + ';base64,' + i.json.base64
}));
return [{ json: { sukses: true, jumlah: hasil.length, hasil } }];

// Field binary yang diharapkan dari web app: 'pdf'
const item = $input.first();
const binari = item.binary || {};
if (!binari.pdf) {
  return [{ json: { sukses: false, error: 'File PDF tidak ditemukan. Pastikan web app upload PDF dengan nama field: pdf', lewatiGemini: true } }];
}
const buffer = await this.helpers.getBinaryDataBuffer(0, 'pdf');
return [{
  json: {
    pdfB64: buffer.toString('base64'),
    pdfMime: binari.pdf.mimeType || 'application/pdf'
  }
}];

const resp = $input.first().json;

// Kalau node Gemini gagal (network/HTTP error via onError:continueRegularOutput),
// n8n menaruh detail error di resp.error / resp.message.
if (resp?.error) {
  return [{ json: { sukses: false, error: 'Gemini API error: ' + JSON.stringify(resp.error) } }];
}

const parts = resp?.candidates?.[0]?.content?.parts || [];
const teks = parts.map(p => p.text).filter(Boolean).join('');

if (!teks) {
  return [{ json: { sukses: false, error: 'Tidak ada teks hasil ekstraksi dari Gemini. Respons mentah: ' + JSON.stringify(resp).slice(0, 500) } }];
}

let data;
try {
  data = JSON.parse(teks);
} catch (e) {
  return [{ json: { sukses: false, error: 'Gagal membaca hasil ekstraksi Gemini: ' + e.message + '. Teks mentah: ' + teks.slice(0, 500) } }];
}

return [{
  json: {
    sukses: true,
    judul_produk: data.judul_produk || '',
    tagline: data.tagline || '',
    deskripsi: data.deskripsi || '',
    spesifikasi: data.spesifikasi || '',
    key_point_sell: data.key_point_sell || '',
    cara_penggunaan: data.cara_penggunaan || '',
    subjek: data.subjek || '',
    improvement: data.improvement || '',
    background: data.background || '',
    warna: data.warna || ''
  }
}];

// Field binary yang diharapkan dari web app: 'gambar' (gambar hasil generate yang mau diedit AI)
// Field text: instruksi (perintah edit dalam bahasa natural dari user)
const item = $input.first();
const binari = item.binary || {};
if (!binari.gambar) {
  return [{ json: { sukses: false, error: 'File gambar tidak ditemukan. Pastikan web app upload gambar dengan nama field: gambar', lewatiGemini: true } }];
}
const body = item.json.body || item.json;
const instruksi = (body.instruksi || '').trim();
if (!instruksi) {
  return [{ json: { sukses: false, error: 'Instruksi edit kosong. Isi dulu perintah editnya.', lewatiGemini: true } }];
}
const buffer = await this.helpers.getBinaryDataBuffer(0, 'gambar');
return [{
  json: {
    gambarB64: buffer.toString('base64'),
    gambarMime: binari.gambar.mimeType || 'image/png',
    instruksi
  }
}];

const resp = $input.first().json;

if (resp?.error) {
  return [{ json: { sukses: false, error: 'Gemini API error: ' + JSON.stringify(resp.error) } }];
}

const parts = resp?.candidates?.[0]?.content?.parts || [];
const imgPart = parts.find(p => p.inlineData || p.inline_data);
if (!imgPart) {
  return [{ json: { sukses: false, error: 'AI tidak menghasilkan gambar. Coba ubah instruksi edit.' } }];
}
const d = imgPart.inlineData || imgPart.inline_data;
return [{
  json: {
    sukses: true,
    image: 'data:' + (d.mimeType || d.mime_type || 'image/png') + ';base64,' + d.data
  }
}];
